import{f as a,o as n,c as t,a2 as e}from"./chunks/framework.DHYrF-q6.js";const b=JSON.parse('{"title":"技术方案设计","description":"","frontmatter":{},"headers":[],"relativePath":"tech-management/technical-design.md","filePath":"tech-management/technical-design.md","lastUpdated":1780927158000}'),i={name:"tech-management/technical-design.md"};function l(r,s,p,o,d,h){return n(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="技术方案设计" tabindex="-1">技术方案设计 <a class="header-anchor" href="#技术方案设计" aria-label="Permalink to &quot;技术方案设计&quot;">​</a></h1><blockquote><p>技术方案设计是 P7+/技术专家最核心的硬能力之一。从技术选型到架构评审、从技术文档写作到 RFC 流程管理，每一个环节都体现着一个技术管理者的判断力和工程素养。本模块聚焦实战方法论，而非纸上谈兵。</p></blockquote><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>考察点</th><th>重要程度</th><th>面试频率</th><th>掌握目标</th></tr></thead><tbody><tr><td>技术选型方法论</td><td>⭐⭐⭐</td><td>极高</td><td>能描述完整的选型框架和决策维度</td></tr><tr><td>架构评审 ADR</td><td>⭐⭐⭐</td><td>高</td><td>能解释 ADR 的作用、格式和落地经验</td></tr><tr><td>技术文档写作</td><td>⭐⭐</td><td>高</td><td>能说明技术文档的分类、模板和写作原则</td></tr><tr><td>RFC 流程</td><td>⭐⭐</td><td>中高</td><td>能描述 RFC 的完整生命周期和推动经验</td></tr><tr><td>风险评估与应急预案</td><td>⭐⭐⭐</td><td>高</td><td>能举例说明风险矩阵和回滚方案的制定</td></tr></tbody></table><h2 id="与现有模块的关系" tabindex="-1">与现有模块的关系 <a class="header-anchor" href="#与现有模块的关系" aria-label="Permalink to &quot;与现有模块的关系&quot;">​</a></h2><ul><li><a href="./../software-engineering/design-principles">软件工程 -- 设计原则</a> -- 设计原则（SOLID、KISS、YAGNI）是技术方案设计的理论根基</li><li><a href="./../software-engineering/code-quality">软件工程 -- 代码质量</a> -- 技术方案的质量最终体现在代码质量上</li><li><a href="./">技术管理 -- 总览</a> -- 技术方案设计是技术管理者角色能力的核心组成部分</li></ul><hr><h2 id="一、技术选型方法论" tabindex="-1">一、技术选型方法论 <a class="header-anchor" href="#一、技术选型方法论" aria-label="Permalink to &quot;一、技术选型方法论&quot;">​</a></h2><h3 id="_1-1-选型的本质-在约束条件下做最优决策" tabindex="-1">1.1 选型的本质：在约束条件下做最优决策 <a class="header-anchor" href="#_1-1-选型的本质-在约束条件下做最优决策" aria-label="Permalink to &quot;1.1 选型的本质：在约束条件下做最优决策&quot;">​</a></h3><p>技术选型不是&quot;哪个技术最好&quot;，而是&quot;哪个技术在当前约束下最优&quot;。面试中，面试官想听到的不是&quot;我用Kafka因为它吞吐量高&quot;，而是&quot;在给定的团队规模、业务场景和时间窗口下，为什么选择A而不是B&quot;。</p><h3 id="_1-2-技术选型五维评估模型" tabindex="-1">1.2 技术选型五维评估模型 <a class="header-anchor" href="#_1-2-技术选型五维评估模型" aria-label="Permalink to &quot;1.2 技术选型五维评估模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>权重（典型）</th><th>评估要素</th></tr></thead><tbody><tr><td><strong>业务匹配度</strong></td><td>30%</td><td>功能满足度、非功能性需求（延迟/吞吐/一致性）、未来演进方向</td></tr><tr><td><strong>团队能力</strong></td><td>25%</td><td>现有技术栈、学习曲线、社区中的人才供给、内部是否有专家</td></tr><tr><td><strong>运维成本</strong></td><td>20%</td><td>部署复杂度、监控成熟度、故障恢复能力、是否需要专人维护</td></tr><tr><td><strong>生态成熟度</strong></td><td>15%</td><td>社区活跃度、文档质量、第三方集成、大厂使用案例</td></tr><tr><td><strong>长期风险</strong></td><td>10%</td><td>开源协议、商业依赖风险、技术生命周期阶段</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">面试高频陷阱</p><p>永远不要只说技术优势而忽略成本。面试官最想听到的是你对<strong>权衡</strong>的思考——A方案快但不稳定，B方案稳定但重——你为什么在这样的权衡下做出选择。没有&quot;完美的方案&quot;，只有&quot;在当前约束下合理的方案&quot;。</p></div><h3 id="_1-3-典型选型案例" tabindex="-1">1.3 典型选型案例 <a class="header-anchor" href="#_1-3-典型选型案例" aria-label="Permalink to &quot;1.3 典型选型案例&quot;">​</a></h3><p><strong>案例：消息队列选型</strong></p><p>某电商团队面临消息队列选型。业务需求是订单状态流转，异步通知下游（库存、物流、通知）。日均订单量50万，峰值约为日均的3倍。</p><table tabindex="0"><thead><tr><th>候选方案</th><th>优势</th><th>劣势</th><th>团队评价</th></tr></thead><tbody><tr><td>RabbitMQ</td><td>协议成熟，运维简单，延迟低</td><td>吞吐量上限约2-3万/s</td><td>团队中有两人用过</td></tr><tr><td>Kafka</td><td>吞吐量极高，持久化好</td><td>运维复杂，延迟稍高，团队没有人用过</td><td>需额外1-2个月学习</td></tr><tr><td>RocketMQ</td><td>阿里出品，中文文档好，事务消息</td><td>社区门槛降低后变冷</td><td>学习成本中等</td></tr></tbody></table><p>最终选择：RabbitMQ。理由：当前并发量（峰值约1800条/s）远未碰到RabbitMQ的吞吐量上限；团队已有的运维经验能降低故障风险；RocketMQ虽好但社区活跃度下降带来长期维护风险。</p><p><strong>面试回答关键</strong>：这个决策不是永久的——如果未来订单量增长到日均500万，RabbitMQ达到瓶颈时，方案应该切换到Kafka。技术选型要留好演进路径。</p><hr><h2 id="二、架构评审-adr-architecture-decision-record" tabindex="-1">二、架构评审 ADR（Architecture Decision Record） <a class="header-anchor" href="#二、架构评审-adr-architecture-decision-record" aria-label="Permalink to &quot;二、架构评审 ADR（Architecture Decision Record）&quot;">​</a></h2><h3 id="_2-1-什么是-adr" tabindex="-1">2.1 什么是 ADR <a class="header-anchor" href="#_2-1-什么是-adr" aria-label="Permalink to &quot;2.1 什么是 ADR&quot;">​</a></h3><p>ADR 是一种轻量级的架构决策记录方式——每做一个重要的架构决策，就写一篇短文档记录：<strong>为什么做这个决策、背景是什么、考虑了哪些替代方案、选择了什么、后果是什么</strong>。</p><h3 id="_2-2-adr-的标准格式" tabindex="-1">2.2 ADR 的标准格式 <a class="header-anchor" href="#_2-2-adr-的标准格式" aria-label="Permalink to &quot;2.2 ADR 的标准格式&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># ADR-001: 选择 RabbitMQ 作为消息中间件</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 状态</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">已接受 / 已废弃（被 ADR-XXX 替代） / 提议中</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 背景</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">当前系统需要异步解耦订单模块与下游服务（库存、物流、通知）。</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">日均订单量50万，峰值约为日均3倍。团队4人，2人有RabbitMQ使用经验。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 决策</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">采用 RabbitMQ 作为消息中间件。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 考虑的替代方案</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;"> **Kafka**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 吞吐量高但运维复杂，团队无经验，学习成本约1-2个月</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;"> **RocketMQ**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 功能丰富但社区活跃度下降</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;"> **Redis Stream**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: 轻量但持久化能力和消息可靠性不如专用MQ</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 后果</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 正面：快速上手，运维简单，满足当前吞吐量需求</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 负面：当订单量增长到日均500万时需要迁移到Kafka</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 风险：单机RabbitMQ的可用性风险——第一期手动切换，第二期引入镜像队列</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h3 id="_2-3-adr-的价值与落地" tabindex="-1">2.3 ADR 的价值与落地 <a class="header-anchor" href="#_2-3-adr-的价值与落地" aria-label="Permalink to &quot;2.3 ADR 的价值与落地&quot;">​</a></h3><table tabindex="0"><thead><tr><th>价值维度</th><th>说明</th></tr></thead><tbody><tr><td><strong>防止重复讨论</strong></td><td>&quot;为什么当时选了RabbitMQ？&quot;不再需要去翻聊天记录</td></tr><tr><td><strong>新人上手</strong></td><td>新人通过读ADR就能理解系统为什么长这样</td></tr><tr><td><strong>决策回溯</strong></td><td>当约束条件变化时（如订单量翻了10倍），ADR提供了&quot;重新评估&quot;的锚点</td></tr><tr><td><strong>架构治理</strong></td><td>ADR 的&quot;状态&quot;字段让废弃决策有迹可循</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">落地经验</p><p>ADR 不需要写成论文。每个 ADR 控制在 1-2 页。存放到项目仓库的 <code>docs/adr/</code> 目录下，编号递增。不要等到&quot;完美&quot;再写——决策做出后就写，即使不完美也是真实的上下文记录。</p></div><hr><h2 id="三、技术文档写作" tabindex="-1">三、技术文档写作 <a class="header-anchor" href="#三、技术文档写作" aria-label="Permalink to &quot;三、技术文档写作&quot;">​</a></h2><h3 id="_3-1-技术文档的四层分类" tabindex="-1">3.1 技术文档的四层分类 <a class="header-anchor" href="#_3-1-技术文档的四层分类" aria-label="Permalink to &quot;3.1 技术文档的四层分类&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一层：设计文档</span></span>
<span class="line"><span>  └── 写给谁：架构师、Tech Lead</span></span>
<span class="line"><span>  └── 什么时候写：做重大技术决策前</span></span>
<span class="line"><span>  └── 格式参考：ADR、技术方案设计书</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层：接口文档</span></span>
<span class="line"><span>  └── 写给谁：调用方开发者</span></span>
<span class="line"><span>  └── 什么时候写：API 设计完成后、编码前（Contract-First）</span></span>
<span class="line"><span>  └── 格式参考：OpenAPI/Swagger、Proto 文件 + 注释</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层：运维文档</span></span>
<span class="line"><span>  └── 写给谁：运维、SRE、On-Call 值班</span></span>
<span class="line"><span>  └── 什么时候写：上线前、每次故障后更新</span></span>
<span class="line"><span>  └── 格式参考：Runbook、故障手册、监控大盘说明</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四层：知识文档</span></span>
<span class="line"><span>  └── 写给谁：新入职的团队成员</span></span>
<span class="line"><span>  └── 什么时候写：持续迭代</span></span>
<span class="line"><span>  └── 格式参考：模块README、技术分享记录、FAQ</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h3 id="_3-2-技术文档写作三原则" tabindex="-1">3.2 技术文档写作三原则 <a class="header-anchor" href="#_3-2-技术文档写作三原则" aria-label="Permalink to &quot;3.2 技术文档写作三原则&quot;">​</a></h3><ol><li><strong>读者优先</strong>：先定义&quot;谁在读&quot;，再决定怎么写。给PM看的和给运维看的应该是两篇不同的文档。</li><li><strong>场景驱动</strong>：不要罗列&quot;系统有哪些功能&quot;，而是&quot;用户要做X时，系统怎么处理&quot;。</li><li><strong>持续更新</strong>：文档的敌人是&quot;过期&quot;。与其写十篇不更新的文档，不如维护三篇永远准确的核心文档。</li></ol><div class="warning custom-block"><p class="custom-block-title">常见错误</p><p>&quot;看代码就知道了，不用写文档。&quot;——这是典型的IC思维。作为技术管理者，文档不只是一个参考材料，它更是<strong>团队知识传递的载体</strong>和<strong>架构质量的检查工具</strong>。如果你的设计文档写得一团糟，很可能设计本身也是一团糟。</p></div><hr><h2 id="四、rfc-流程" tabindex="-1">四、RFC 流程 <a class="header-anchor" href="#四、rfc-流程" aria-label="Permalink to &quot;四、RFC 流程&quot;">​</a></h2><h3 id="_4-1-rfc-request-for-comments-的生命周期" tabindex="-1">4.1 RFC（Request for Comments）的生命周期 <a class="header-anchor" href="#_4-1-rfc-request-for-comments-的生命周期" aria-label="Permalink to &quot;4.1 RFC（Request for Comments）的生命周期&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提出（Proposal）</span></span>
<span class="line"><span>  └── 任何人可以提出 RFC，技术管理者把关是否需要正式流程</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>讨论（Discussion）</span></span>
<span class="line"><span>  └── 给相关方1-5个工作日的Review时间</span></span>
<span class="line"><span>  └── 异步评论为主，复杂议题安排同步讨论</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>决策（Decision）</span></span>
<span class="line"><span>  └── 技术管理者或架构委员会做出最终决策</span></span>
<span class="line"><span>  └── 记录&quot;批准/拒绝/需修改&quot;及理由</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>公示（Announcement）</span></span>
<span class="line"><span>  └── 在全团队范围内通知决策结果和要点</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>落地（Implementation）</span></span>
<span class="line"><span>  └── RFC 转化为具体的技术方案文档（即 ADR）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h3 id="_4-2-rfc-流程的落地要点" tabindex="-1">4.2 RFC 流程的落地要点 <a class="header-anchor" href="#_4-2-rfc-流程的落地要点" aria-label="Permalink to &quot;4.2 RFC 流程的落地要点&quot;">​</a></h3><p>在中小团队（5-15人），RFC流程不需要很重：</p><ul><li><strong>触发条件</strong>：涉及跨模块的影响、引入新的技术栈或中间件、需要团队达成共识的设计决策</li><li><strong>评审周期</strong>：普通RFC 2个工作日，重大RFC 5个工作日</li><li><strong>决策机制</strong>：在中小团队，通常由Tech Lead做最终决策（而非投票制，避免&quot;设计委员会&quot;的效率问题）</li><li><strong>关键原则</strong>：不同意可以提出替代方案，但一旦决策做出，全团队执行</li></ul><hr><h2 id="五、风险评估" tabindex="-1">五、风险评估 <a class="header-anchor" href="#五、风险评估" aria-label="Permalink to &quot;五、风险评估&quot;">​</a></h2><h3 id="_5-1-技术方案的风险矩阵" tabindex="-1">5.1 技术方案的风险矩阵 <a class="header-anchor" href="#_5-1-技术方案的风险矩阵" aria-label="Permalink to &quot;5.1 技术方案的风险矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风险类别</th><th>具体风险</th><th>概率</th><th>影响</th><th>缓解措施</th></tr></thead><tbody><tr><td><strong>技术风险</strong></td><td>新技术栈学习曲线超预期</td><td>中</td><td>中</td><td>安排核心成员先做POC</td></tr><tr><td><strong>依赖风险</strong></td><td>第三方服务不稳定或接口变更</td><td>高</td><td>高</td><td>增加熔断降级、签订SLA</td></tr><tr><td><strong>人力风险</strong></td><td>关键成员离职或请假</td><td>中</td><td>高</td><td>保证每个模块至少两人熟悉</td></tr><tr><td><strong>容量风险</strong></td><td>实际流量远超预估</td><td>低</td><td>高</td><td>提前准备水平扩容方案</td></tr><tr><td><strong>兼容风险</strong></td><td>老版本客户端不兼容新接口</td><td>中</td><td>中</td><td>接口版本化，灰度发布</td></tr></tbody></table><h3 id="_5-2-应急预案的编写模板" tabindex="-1">5.2 应急预案的编写模板 <a class="header-anchor" href="#_5-2-应急预案的编写模板" aria-label="Permalink to &quot;5.2 应急预案的编写模板&quot;">​</a></h3><p>每个重大上线必须有回滚方案（Rollback Plan），且要在上线评审会上重述一遍：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 回滚触发条件（什么情况下应该回滚？）</span></span>
<span class="line"><span>   - 核心指标下降超过X%</span></span>
<span class="line"><span>   - 错误率超过X%</span></span>
<span class="line"><span>   - 用户投诉超过X条/小时</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 回滚步骤（操作人、操作步骤、预估时间）</span></span>
<span class="line"><span>   - 步骤1: 通过配置中心关闭新功能开关（&lt; 1分钟）</span></span>
<span class="line"><span>   - 步骤2: 如开关无效，回滚到上个版本的镜像（&lt; 5分钟）</span></span>
<span class="line"><span>   - 步骤3: 验证核心链路正常（&lt; 3分钟）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 数据回滚方案（如涉及数据变更）</span></span>
<span class="line"><span>   - 是否有数据兼容性保证？</span></span>
<span class="line"><span>   - 是否需要数据回滚脚本？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 回滚后的通知机制</span></span>
<span class="line"><span>   - 通知相关团队和业务方</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><hr><h2 id="⭐-面试高频问题" tabindex="-1">⭐ 面试高频问题 <a class="header-anchor" href="#⭐-面试高频问题" aria-label="Permalink to &quot;⭐ 面试高频问题&quot;">​</a></h2><h3 id="q1-请描述你的技术选型方法论。能否举例说明" tabindex="-1">Q1：请描述你的技术选型方法论。能否举例说明？ <a class="header-anchor" href="#q1-请描述你的技术选型方法论。能否举例说明" aria-label="Permalink to &quot;Q1：请描述你的技术选型方法论。能否举例说明？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>我的方法论是&quot;约束-选项-评估-决策-记录&quot;五步法：</p><ol><li><strong>明确约束</strong>：业务场景、团队能力、时间窗口、预算、现有系统兼容性</li><li><strong>列出选项</strong>：至少3个候选方案，包括&quot;维持现状&quot;</li><li><strong>多维评估</strong>：用五维评估模型（业务匹配度、团队能力、运维成本、生态成熟度、长期风险）为每个选项打分</li><li><strong>做出决策</strong>：在团队内达成共识，记录决策理由</li><li><strong>写入ADR</strong>：将决策永久记录，方便未来回溯</li></ol><p>实战案例：[分享你的一次实际选型经历，重点说清楚权衡过程]</p><h3 id="q2-什么是-adr-你们团队是怎么用的" tabindex="-1">Q2：什么是 ADR？你们团队是怎么用的？ <a class="header-anchor" href="#q2-什么是-adr-你们团队是怎么用的" aria-label="Permalink to &quot;Q2：什么是 ADR？你们团队是怎么用的？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>ADR（Architecture Decision Record）是一种轻量级的架构决策记录。每做一个重要决策，我们就在 <code>docs/adr/</code> 下写一篇简短的记录，包含：背景、决策、考虑的替代方案、后果（正面和负面）。</p><p>我们团队的原则是：不追求完美，但追求&quot;有记录&quot;。如果每次决策讨论完都没有文档，半年后团队就忘了&quot;为什么这么设计&quot;——ADR 解决了这个&quot;考古&quot;问题。落地时最关键的一点是：决策者自己写 ADR，不要转交给其他人——转交了就会丢失决策的上下文和微妙考量。</p><h3 id="q3-你怎么判断一份技术方案的质量" tabindex="-1">Q3：你怎么判断一份技术方案的质量？ <a class="header-anchor" href="#q3-你怎么判断一份技术方案的质量" aria-label="Permalink to &quot;Q3：你怎么判断一份技术方案的质量？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>我看技术方案时有六个检查点：</p><ol><li><strong>目标是否清晰</strong>：第一页能不能说清楚要解决什么问题，ROI是什么</li><li><strong>是否有备选方案</strong>：单一方案说明思考不够充分，至少要有两个备选方案和放弃理由</li><li><strong>非功能性需求是否覆盖</strong>：不只是&quot;功能能做出来&quot;，还要考虑性能、安全、可观测性、容错</li><li><strong>是否画了核心链路图</strong>：一图胜千言，时序图/架构图是技术方案的骨架</li><li><strong>是否写了风险点</strong>：有没有主动识别风险？有没有回滚方案？</li><li><strong>是否可执行</strong>：能不能拆出3-5个独立的开发任务，每个任务有预估工时</li></ol><p>如果有3个以上检查点不合格，我会让作者拿回去重写——这不是不近人情，而是方案质量的底线。</p><h3 id="q4-你怎么推动-rfc-流程在团队中落地" tabindex="-1">Q4：你怎么推动 RFC 流程在团队中落地？ <a class="header-anchor" href="#q4-你怎么推动-rfc-流程在团队中落地" aria-label="Permalink to &quot;Q4：你怎么推动 RFC 流程在团队中落地？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>推动的关键是<strong>先小范围做示范，再逐步扩大</strong>：</p><ol><li>我作为 Tech Lead 先写 2-3 篇 RFC 出来，让团队看到&quot;原来是这个格式&quot;</li><li>每次评审会上提及：&quot;这个决策有没有RFC？&quot;形成习惯</li><li>把 RFC 的 Review 过程做成异步的（通过文档评论），不额外开会</li><li>降低门槛：RFC 不要求完美——一个核心决策 + 两个备选方案分析就足够</li><li>建立正循环：当团队成员发现&quot;上次那个RFC帮我挡掉了PM的无理需求&quot;时，他们自然会愿意写</li></ol><p>最难的其实是&quot;什么时候需要RFC&quot;的判断。我的规则是：如果这个决策会影响超过3个人或持续超过6个月，就应该写RFC。</p><h3 id="q5-一个大项目上线-你怎么做风险评估和应急准备" tabindex="-1">Q5：一个大项目上线，你怎么做风险评估和应急准备？ <a class="header-anchor" href="#q5-一个大项目上线-你怎么做风险评估和应急准备" aria-label="Permalink to &quot;Q5：一个大项目上线，你怎么做风险评估和应急准备？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>我的流程分为四步：</p><ol><li><p><strong>上线前评审</strong>：拉上相关方（开发、测试、运维、产品），对照风险清单逐项确认。重点关注数据变更、接口兼容性、第三方依赖变化。</p></li><li><p><strong>灰度策略</strong>：按用户比例逐步放量（1% → 10% → 50% → 100%），每个阶段观察核心指标至少30分钟。宁可多花半天时间灰度，也不要全量上去后紧急回滚。</p></li><li><p><strong>回滚方案</strong>：每个上线必须有明确的回滚条件（错误率&gt;X%、延迟&gt;Xms）、回滚步骤（精确到每分钟做什么操作）、回滚验证（回滚后怎么确认系统恢复正常）。</p></li><li><p><strong>值守机制</strong>：上线后核心开发人员至少值守1小时，确保有异常时能第一时间响应。我个人的原则是：<strong>谁写的代码谁值守，谁做的决策谁负责</strong>——上线不是&quot;扔过墙&quot;，而是责任的延续。</p></li></ol><p>如果面试官追问&quot;有没有上线失败的案例&quot;——一定要诚实说一个，重点放在复盘结论和后续改进上，而不是把锅甩给&quot;测试没测好&quot;或&quot;运维操作失误&quot;。</p><h3 id="q6-你遇到过技术方案被否决的情况吗-怎么处理的" tabindex="-1">Q6：你遇到过技术方案被否决的情况吗？怎么处理的？ <a class="header-anchor" href="#q6-你遇到过技术方案被否决的情况吗-怎么处理的" aria-label="Permalink to &quot;Q6：你遇到过技术方案被否决的情况吗？怎么处理的？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>当然遇到过。有一次我主导的技术方案在评审会上被架构师否决了，理由是&quot;耦合了太多业务逻辑到基础设施层&quot;。</p><p>处理方式：第一，先冷静听对方说完理由——不要在情绪上防御，把评审当成改进自己方案的机会。第二，会后我用对方指出的问题重新审视了一遍方案，确实发现有三处耦合可以解耦。第三，我当天就把修改后的方案发回去，附上&quot;感谢指正，修改后的方案解决了XX问题&quot;。</p><p>这件事让我学到的是：技术方案被否决不是对你的否定，而是对你工作的<strong>质量检查</strong>。一个管理者如果受不了自己的方案被质疑，那他带团队时也会受不了别人的不同意见。如果你想听到&quot;我的方案从来没被否决过&quot;——那就说明你从来没有提交过有任何风险的方案，这并不是好信号。</p><h3 id="q7-如何推动团队写好技术文档" tabindex="-1">Q7：如何推动团队写好技术文档？ <a class="header-anchor" href="#q7-如何推动团队写好技术文档" aria-label="Permalink to &quot;Q7：如何推动团队写好技术文档？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><p>这个问题背后折射的是&quot;技术文档谁都不爱写&quot;的现实。我的策略分三步：</p><ol><li><p><strong>降低门槛</strong>：不要要求&quot;完整的设计文档&quot;，而是先用模板驱动——一个标准的方案模板（背景-方案-风险-排期）比一张白纸容易写得多。</p></li><li><p><strong>绑定流程</strong>：文档不只是&quot;写完看的&quot;，而是和具体流程绑定——例如，没有方案文档不允许进入开发阶段，没有Runbook不允许上线。文档有了真实价值，写作意愿自然上升。</p></li><li><p><strong>以身作则</strong>：作为技术管理者，你自己的方案和Code Review评论是最好的模板。如果你自己的Code Review永远只是&quot;LGTM&quot;三个字母，就不要指望团队成员写出有深度的设计文档。</p></li></ol>`,84)])])}const u=a(i,[["render",l]]);export{b as __pageData,u as default};
